import anthropic, threading

client = anthropic.Anthropic()

class CancellableAgentLoop:
    """
    Agent loop with cooperative cancellation.
    Call cancel() from any thread to stop after the current step.
    """

    def __init__(self):
        self._cancel = threading.Event()

    def cancel(self):
        self._cancel.set()
        print("[CANCEL] Cancellation requested — will stop after current step")

    def run(self, task: str, tools: list[dict]) -> str:
        messages = [{"role": "user", "content": task}]

        for step in range(100):
            # Check cancellation before each step
            if self._cancel.is_set():
                return f"Cancelled at step {step} — task incomplete"

            response = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=1024,
                tools=tools,
                messages=messages,
            )

            if response.stop_reason == "end_turn":
                return response.content[0].text if response.content else ""

            tool_results = []
            for block in response.content:
                if block.type != "tool_use":
                    continue
                # Check cancellation before each tool call
                if self._cancel.is_set():
                    return f"Cancelled before {block.name} — task incomplete"
                # Execute tool (placeholder)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": f"executed {block.name}",
                })

            messages.append({"role": "assistant", "content": response.content})
            messages.append({"role": "user", "content": tool_results})

        return "Step limit reached"

import anthropic, json, time
from pathlib import Path

client = anthropic.Anthropic()

class AuditLogger:
    """Append-only JSONL audit log for agent tool calls."""

    def __init__(self, log_path: str):
        self.path = Path(log_path)
        self.path.parent.mkdir(parents=True, exist_ok=True)

    def log(self, event_type: str, data: dict) -> None:
        entry = {
            "ts": time.time(),
            "event": event_type,
            **data,
        }
        with self.path.open("a") as f:
            f.write(json.dumps(entry) + "\n")

    def replay(self) -> list[dict]:
        """Load all log entries for review or rollback."""
        if not self.path.exists():
            return []
        return [json.loads(line) for line in self.path.read_text().splitlines()]


def audited_agent_loop(task: str, tools: list[dict], log_path: str) -> str:
    """Agent loop that logs every tool call and its result."""
    logger = AuditLogger(log_path)
    logger.log("task_start", {"task": task})
    messages = [{"role": "user", "content": task}]

    for step in range(50):
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            tools=tools,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            result = response.content[0].text if response.content else ""
            logger.log("task_complete", {"result": result[:200]})
            return result

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            logger.log("tool_call", {
                "step": step,
                "tool": block.name,
                "input": block.input,
            })
            # Execute tool (placeholder)
            result = f"executed {block.name}"
            logger.log("tool_result", {
                "step": step,
                "tool": block.name,
                "result": result,
            })
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": result,
            })

        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})

    logger.log("task_timeout", {"steps": 50})
    return "Step limit reached"
